DROP TABLE IF EXISTS `aircraft_types`;
CREATE TABLE `aircraft_types`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '机型ID',
  `code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '机型代码：SW100, SW300, SW700',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '机型名称：SkyWing 100, SkyWing 300, SkyWing 700',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '机型分类：SMALL-小型, MEDIUM-中型, LARGE-大型',
  `total_seats` int NOT NULL COMMENT '总座位数',
  `first_class_seats` int NOT NULL DEFAULT 0 COMMENT '头等舱座位数',
  `business_class_seats` int NOT NULL DEFAULT 0 COMMENT '商务舱座位数',
  `economy_class_seats` int NOT NULL DEFAULT 0 COMMENT '经济舱座位数',
  `first_class_start_row` int NULL DEFAULT NULL COMMENT '头等舱起始排号',
  `first_class_end_row` int NULL DEFAULT NULL COMMENT '头等舱结束排号',
  `business_class_start_row` int NULL DEFAULT NULL COMMENT '商务舱起始排号',
  `business_class_end_row` int NULL DEFAULT NULL COMMENT '商务舱结束排号',
  `economy_class_start_row` int NOT NULL COMMENT '经济舱起始排号',
  `economy_class_end_row` int NOT NULL COMMENT '经济舱结束排号',
  `layout_config` json NULL COMMENT '座位布局配置（JSON格式）',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `economy_class_base_price` decimal(10, 2) NOT NULL DEFAULT 800.00 COMMENT '经济舱基础价格',
  `business_class_base_price` decimal(10, 2) NOT NULL DEFAULT 2000.00 COMMENT '商务舱基础价格',
  `first_class_base_price` decimal(10, 2) NOT NULL DEFAULT 5000.00 COMMENT '头等舱基础价格',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `code`(`code` ASC) USING BTREE,
  INDEX `idx_code`(`code` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '机型配置表' ROW_FORMAT = Dynamic;

