  `seat_number` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '座位号，如 \"1A\", \"12C\", \"3F\"',
  `seat_row` int NOT NULL COMMENT '排号，如 1, 12, 3',
