  `seat_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'NORMAL' COMMENT '座位类型：NORMAL-普通, WINDOW-靠窗, AISLE-过道, EMERGENCY_EXIT-紧急出口, LEGROOM-腿部空间大',
  `price_surcharge` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '座位加价（相对舱位基础价）',
  `is_available` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否可用（用于维护等，TRUE-可用, FALSE-不可用）',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_flight_seat`(`flight_id` ASC, `seat_number` ASC) USING BTREE,
  UNIQUE INDEX `UKg0s2pi4n8w53h21tly5yh8yvb`(`flight_id` ASC, `seat_number` ASC) USING BTREE,
  INDEX `idx_flight_id`(`flight_id` ASC) USING BTREE,
