  INDEX `idx_seat_number`(`seat_number` ASC) USING BTREE,
  INDEX `idx_seat_type`(`seat_type` ASC) USING BTREE,
  INDEX `idx_is_available`(`is_available` ASC) USING BTREE,
  CONSTRAINT `seats_ibfk_1` FOREIGN KEY (`flight_id`) REFERENCES `flights` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 4901 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '具体座位表' ROW_FORMAT = Dynamic;

